export function seedProductionEntries(db) {
  const existing = db.prepare('SELECT COUNT(*) as c FROM production_entries').get().c;
  if (existing > 0) return;

  const insert = db.prepare(`
    INSERT INTO production_entries (id, date, team, room, product_name, mo_number, lot_number, start_time, end_time, quantity_completed, people_count, notes, submitted_by, qa_signoff_by, qa_signoff_at, qa_notes)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);

  const tx = db.transaction(() => {
    for (const row of ENTRIES) {
      insert.run(uuid(), ...row);
    }
  });
  tx();

  console.log(`[seed] Imported ${ENTRIES.length} production entries`);
}
